framework_css:
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Source+Sans+3:wght@300;400;500;600;700&family=Source+Code+Pro:wght@400;600&display=swap');

:root {
  --color-primary-black: #000000;
  --color-primary-gold: #C79A3A;
  --color-primary-gold-dark: #A8842F;
  --color-secondary-light-gray: #F2F2F2;
  --color-secondary-white: #FFFFFF;
  --color-accent-red: #F6524B;
  --color-accent-amber: #FFB000;
  --color-border-subtle: #D6D6D6;
  --color-text-main: #000000;

  --color-success: #22A85A;
  --color-error: #D32F2F;
  --color-warning: #F9A825;
  --color-info: #1976D2;

  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 32px;
  --font-size-h2: 26px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --header-z: 1000;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-secondary-light-gray);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

.site-body {
  min-height: 100vh;
}

.site-header {
  position: relative;
  z-index: var(--header-z);
}

/* Top black bar */
.top-bar {
  background-color: var(--color-primary-black);
  color: var(--color-secondary-white);
  border-bottom: 2px solid var(--color-primary-gold);
  font-family: var(--font-heading);
  text-transform: uppercase;
  font-size: var(--font-size-small);
}

.top-bar-inner {
  display: flex;
  align-items: center;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.top-bar-brand {
  font-weight: 700;
  letter-spacing: 0.08em;
}

.top-bar-message {
  flex: 1;
  text-align: center;
  font-weight: 500;
}

.top-bar-cta {
  display: flex;
  justify-content: flex-end;
  min-width: 170px;
}

.cta-outer {
  display: inline-block;
  background-color: var(--color-primary-black);
  padding: 3px;
  border-radius: 4px;
  border: 2px solid var(--color-secondary-white);
}

.cta-inner {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-3);
  border-radius: 2px;
  background-color: var(--color-accent-amber);
  color: var(--color-secondary-white);
  font-weight: 700;
  letter-spacing: 0.08em;
}

.cta-icon {
  font-size: 14px;
}

.cta-label {
  white-space: nowrap;
}

/* Gold navigation bar */
.nav-bar {
  background-color: var(--color-primary-gold);
  border-top: 1px solid var(--color-primary-gold-dark);
  border-bottom: 1px solid var(--color-primary-gold-dark);
}

.nav-bar-inner {
  display: flex;
  align-items: stretch;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

/* Brand block */
.brand-block {
  display: inline-flex;
  align-items: center;
  text-decoration: none;
  color: var(--color-secondary-white);
  background-color: var(--color-primary-black);
  border: 2px solid var(--color-primary-gold-dark);
  padding: var(--space-3);
  margin-right: var(--space-4);
  min-width: 220px;
}

.brand-mark {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 72px;
  height: 72px;
  border: 2px solid var(--color-secondary-white);
  margin-right: var(--space-3);
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 14px;
  text-align: center;
  line-height: var(--line-height-tight);
}

.brand-mark-car {
  padding: var(--space-1);
}

.brand-text {
  display: flex;
  flex-direction: column;
  font-family: var(--font-heading);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 13px;
}

.brand-text-line:first-child {
  font-weight: 300;
}

.brand-text-line:last-child {
  font-weight: 700;
}

/* Main nav */
.main-nav {
  flex: 1;
  display: flex;
  justify-content: flex-end;
}

.main-nav-list {
  list-style: none;
  display: flex;
  margin: 0;
  padding: 0;
}

.main-nav-item {
  display: flex;
}

.main-nav-link {
  position: relative;
  display: flex;
  align-items: center;
  padding: var(--space-3) var(--space-4);
  font-family: var(--font-heading);
  font-weight: 600;
  text-transform: uppercase;
  font-size: 15px;
  letter-spacing: 0.08em;
  text-decoration: none;
  color: var(--color-secondary-white);
  border-left: 1px solid var(--color-primary-black);
}

.main-nav-item:first-child .main-nav-link {
  border-left: none;
}

.main-nav-link:hover,
.main-nav-link:focus-visible {
  background-color: rgba(0, 0, 0, 0.08);
}

.main-nav-link.is-active::after {
  content: '';
  position: absolute;
  left: var(--space-4);
  right: var(--space-4);
  bottom: var(--space-2);
  border-bottom: 3px solid var(--color-primary-black);
}

/* Content area */
.site-content {
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

/* Footer */
.site-footer {
  background-color: var(--color-primary-black);
  color: var(--color-secondary-white);
  border-top: 4px solid var(--color-primary-gold);
}

.footer-inner {
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
}

.footer-top {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
  margin-bottom: var(--space-3);
}

.footer-brand-mark {
  font-family: var(--font-heading);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 14px;
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
}

.footer-nav-link {
  position: relative;
  padding-right: var(--space-3);
  margin-right: var(--space-2);
  font-family: var(--font-heading);
  text-transform: uppercase;
  font-size: 13px;
  letter-spacing: 0.08em;
  text-decoration: none;
  color: var(--color-secondary-white);
}

.footer-nav-link::after {
  content: '';
  position: absolute;
  right: 0;
  top: 25%;
  bottom: 25%;
  border-right: 1px solid #555555;
}

.footer-nav-link:last-child {
  margin-right: 0;
  padding-right: 0;
}

.footer-nav-link:last-child::after {
  display: none;
}

.footer-nav-link:hover,
.footer-nav-link:focus-visible {
  text-decoration: underline;
}

.footer-bottom {
  border-top: 1px solid #333333;
  padding-top: var(--space-2);
  margin-top: var(--space-2);
  font-size: var(--font-size-small);
}

.footer-copy {
  margin: 0;
  opacity: 0.8;
}

/* Headings */
h1,
h2,
h3,
h4 {
  font-family: var(--font-heading);
  text-transform: uppercase;
  margin-top: 0;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  color: var(--color-accent-red);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

/* Responsive tweaks */
@media (max-width: 960px) {
  .brand-block {
    padding: var(--space-2) var(--space-3);
    margin-right: var(--space-3);
  }

  .main-nav-link {
    padding: var(--space-2) var(--space-3);
    font-size: 14px;
  }

  .top-bar-message {
    display: none;
  }
}

@media (max-width: 720px) {
  .nav-bar-inner {
    flex-direction: column;
    align-items: stretch;
  }

  .brand-block {
    margin-right: 0;
    margin-bottom: var(--space-2);
    width: 100%;
    justify-content: flex-start;
  }

  .main-nav {
    justify-content: center;
  }

  .main-nav-list {
    flex-wrap: wrap;
    justify-content: center;
  }

  .main-nav-link {
    padding: var(--space-2) var(--space-3);
  }

  .top-bar-inner {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .top-bar-brand {
    width: 100%;
    text-align: left;
  }

  .top-bar-cta {
    width: 100%;
    justify-content: flex-start;
  }
}
